sqlMap.select:
SELECT E.* FROM ( SELECT D.* FROM ( SELECT C.*, ROWNUM AS "rowNum" FROM ( SELECT A.* FROM tbl_usermaster A LEFT JOIN tbl_usermaster_retire B ON A.CN = B.CN AND A.TENANT_ID = B.TENANT_ID AND A.PHYSICALDELIVERYOFFICENAME = B.PHYSICALDELIVERYOFFICENAME WHERE A.TENANT_ID = #tenantID# AND B.CN IS NULL AND A.CN <> 'masteradmin' AND A.DEPARTMENT NOT IN (SELECT CN FROM TBL_DEPTMASTER WHERE DEPT_CD_PATH LIKE '%trash\_dept%' escape '\')
AND A.PHYSICALDELIVERYOFFICENAME = #companyID#
AND (A.DISPLAYNAME LIKE '%' || #pSearchText# || '%' ESCAPE '\' OR A.DESCRIPTION LIKE '%' || #pSearchText# || '%' ESCAPE '\' )
ORDER BY A.DISPLAYNAME ASC ) C ) D
) E WHERE "rowNum" > #rowNum#
)E WHERE "rowNum" <= #oracleListSize#

select.isEqual:
SELECT CN as DEPTID, CASE WHEN (DISPLAYNAME$lang$ = '' OR DISPLAYNAME$lang$ IS NULL) THEN DISPLAYNAME ELSE DISPLAYNAME$lang$ END DEPTNAME, (SELECT 1 FROM DUAL WHERE EXISTS (SELECT CN FROM TBL_DEPTMASTER B WHERE TENANT_ID = #tenantID# AND EXTENSIONATTRIBUTE1 = A.CN
DEPTTREEFLAG = 'Y'
)) AS ISLAST, (SELECT 1 FROM DUAL WHERE EXISTS (SELECT CN FROM TBL_DEPTMASTER B WHERE TENANT_ID = #tenantID# AND A.CN = #deptID#)) AS EXPAND, DEPTLEVEL as DEPTTYPE, EXTENSIONATTRIBUTE1 as HIGHDEPTID FROM TBL_DEPTMASTER A WHERE TENANT_ID = #tenantID# AND CN = #deptID#

select.isNotEqual:
SELECT CN as DEPTID, CASE WHEN (DISPLAYNAME$lang$ = '' OR DISPLAYNAME$lang$ IS NULL) THEN DISPLAYNAME ELSE DISPLAYNAME$lang$ END DEPTNAME, (SELECT 1 FROM DUAL WHERE EXISTS (SELECT CN FROM TBL_DEPTMASTER B WHERE TENANT_ID = #tenantID# AND EXTENSIONATTRIBUTE1 = A.CN
DEPTTREEFLAG = 'Y'
)) AS ISLAST, (SELECT 1 FROM DUAL WHERE EXISTS (SELECT CN FROM TBL_DEPTMASTER B WHERE TENANT_ID = #tenantID# AND A.CN = #deptID#)) AS EXPAND, DEPTLEVEL as DEPTTYPE, EXTENSIONATTRIBUTE1 as HIGHDEPTID FROM TBL_DEPTMASTER A WHERE TENANT_ID = #tenantID# AND EXTENSIONATTRIBUTE1 IN (SELECT C.EXTENSIONATTRIBUTE1 FROM TBL_DEPTMASTER C WHERE TENANT_ID = #tenantID# AND CN = #deptID#) ORDER BY A.EXTENSIONATTRIBUTE15, A.DISPLAYNAME
